function buildMode({ background, foreground, card, muted, mutedForeground, border, primary, primaryForeground, secondary, secondaryForeground, accent, accentForeground, destructive, destructiveForeground, sidebar }) {
	return {
		background,
		foreground,
		card,
		"card-foreground": foreground,
		popover: card,
		"popover-foreground": foreground,
		primary,
		"primary-foreground": primaryForeground,
		secondary,
		"secondary-foreground": secondaryForeground,
		muted,
		"muted-foreground": mutedForeground,
		accent,
		"accent-foreground": accentForeground,
		destructive,
		"destructive-foreground": destructiveForeground,
		border,
		input: border,
		ring: primary,
		"chart-1": primary,
		"chart-2": secondary,
		"chart-3": accent,
		"chart-4": destructive,
		"chart-5": mutedForeground,
		sidebar,
		"sidebar-foreground": foreground,
		"sidebar-primary": primary,
		"sidebar-primary-foreground": primaryForeground,
		"sidebar-accent": accent,
		"sidebar-accent-foreground": accentForeground,
		"sidebar-border": border,
		"sidebar-ring": primary
	};
}
